@@ -0,0 +1,37 @@
+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Archive;
+using Microsoft.Sales.Document;
+using Microsoft.Sales.History;
+using Microsoft.Utilities;
+
+/// <summary>
+/// Codeunit Shpfy Copy Document Handler (ID 30366).
+/// Handles clearing Shopify fields when copying sales documents.
+/// </summary>
+codeunit 30366 "Shpfy Copy Document Handler"
+{
+    /// <summary>
+    /// Clears Shopify-related fields from Sales Header after copying headers from posted documents.
+    /// This event is raised after all header transfer operations (Posted Invoice, Posted Shipment, Posted Return Receipt, Posted Credit Memo).
+    /// </summary>
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopySalesHeaderDone', '', false, false)]
+    local procedure OnAfterCopySalesHeaderDone(var ToSalesHeader: Record "Sales Header"; OldSalesHeader: Record "Sales Header"; FromSalesHeader: Record "Sales Header"; FromSalesShipmentHeader: Record "Sales Shipment Header"; FromSalesInvoiceHeader: Record "Sales Invoice Header"; FromReturnReceiptHeader: Record "Return Receipt Header"; FromSalesCrMemoHeader: Record "Sales Cr.Memo Header"; FromSalesHeaderArchive: Record "Sales Header Archive"; FromDocType: Enum "Sales Document Type From")
+    begin
+        // Only clear Shopify fields when copying from posted documents
+        if FromDocType in ["Sales Document Type From"::"Posted Invoice", "Sales Document Type From"::"Posted Return Receipt", "Sales Document Type From"::"Posted Shipment", "Sales Document Type From"::"Posted Credit Memo"] then
+            ClearShopifyOrderFields(ToSalesHeader);
+    end;
+
+    /// <summary>
+    /// Clears Shopify Order Id and Shopify Order No fields from the provided Sales Header.
+    /// </summary>
+    /// <param name="ToSalesHeader">The Sales Header to clear Shopify fields from.</param>
+    local procedure ClearShopifyOrderFields(var ToSalesHeader: Record "Sales Header")
+    begin
+        if ToSalesHeader."Document Type" in [ToSalesHeader."Document Type"::Invoice, ToSalesHeader."Document Type"::"Credit Memo"] then begin
+            ToSalesHeader."Shpfy Order Id" := 0;
+            ToSalesHeader."Shpfy Order No." := '';
+        end;
+    end;
+}

