+    local procedure UpdateServiceOrderStatus()
+    var
+        ServItemLine2: Record "Service Item Line";
+        ServHeader2: Record "Service Header";
+        ServHeader3: Record "Service Header";
+        RepairStatus: Record "Repair Status";
+        RepairStatusPriority: Integer;
+        UseLineNo: Integer;
+    begin
+        if not ServHeader.Get("Document Type", "Document No.") then
+            exit;
+
+        RepairStatusPriority := Integer.MaxValue();
+        UseLineNo := 0;
+        
+        // Check the current line being inserted/modified
+        if "Repair Status Code" <> '' then begin
+            if RepairStatus.Get("Repair Status Code") then
+                if RepairStatus.Priority < RepairStatusPriority then begin
+                    RepairStatusPriority := RepairStatus.Priority;
+                    UseLineNo := "Line No.";
+                end;
+        end;
+        
+        // Check other lines in the database
+        ServItemLine2.Reset();
+        ServItemLine2.SetRange("Document Type", "Document Type");
+        ServItemLine2.SetRange("Document No.", "Document No.");
+        ServItemLine2.SetFilter("Line No.", '<>%1', "Line No.");
+        ServItemLine2.SetFilter("Repair Status Code", '<>%1', '');
+        if ServItemLine2.Find('-') then
+            repeat
+                if RepairStatus.Get(ServItemLine2."Repair Status Code") then
+                    if RepairStatus.Priority < RepairStatusPriority then begin
+                        RepairStatusPriority := RepairStatus.Priority;
+                        UseLineNo := ServItemLine2."Line No.";
+                    end;
+            until ServItemLine2.Next() = 0;
+
+        if UseLineNo <> 0 then begin
+            if UseLineNo = "Line No." then
+                ServItemLine2 := Rec
+            else
+                ServItemLine2.Get("Document Type", "Document No.", UseLineNo);
+            
+            if RepairStatus.Get(ServItemLine2."Repair Status Code") then begin
+                ServHeader2.Get(Rec."Document Type", Rec."Document No.");
+                ServHeader3 := ServHeader2;
+                if ServHeader2.Status <> RepairStatus."Service Order Status" then begin
+                    ServHeader2.SetValidatingFromLines(true);
+                    if ServHeader2."Finishing Date" = 0D then
+                        ServHeader2.Validate("Finishing Date", ServItemLine2."Finishing Date");
+                    ServHeader2.Validate(Status, RepairStatus."Service Order Status");
+                    if not (ServHeader2.Status = ServHeader2.Status::Finished) then begin
+                        ServHeader2."Finishing Date" := 0D;
+                        ServHeader2."Finishing Time" := 0T;
+                        ServHeader2."Service Time (Hours)" := 0;
+                    end;
+                    ServHeader2.UpdateServiceOrderChangeLog(ServHeader3);
+                    ServHeader2.Modify();
+                end;
+            end;
+        end;
+    end;
